#include <stdio.h>
#include <string.h>
#include <stdbool.h>

bool is_interleave(char *s1, char *s2, char *s3) {
    // Base case: if all strings are empty, return true
    if (*s1 == '\0' && *s2 == '\0' && *s3 == '\0') {
        return true;
    }

    // If s3 is empty but either s1 or s2 is not, return false
    if (*s3 == '\0') {
        return false;
    }

    // Recursive cases
    if (*s1 == *s3 && is_interleave(s1 + 1, s2, s3 + 1)) {
        return true;
    }

    if (*s2 == *s3 && is_interleave(s1, s2 + 1, s3 + 1)) {
        return true;
    }

    return false;
}

int main() {
    char s1[22], s2[22], s3[22];

    // Input strings
    scanf("%s", s1);
    scanf("%s", s2);
    scanf("%s", s3);

