import java.util.Scanner;

class Codechef {
    public static boolean isInterleave(String s1, String s2, String s3) {
        // Base case: if all strings are empty, return true
        if (s1.isEmpty() && s2.isEmpty() && s3.isEmpty()) {
            return true;
        }

        // If s3 is empty but either s1 or s2 is not, return false
        if (s3.isEmpty()) {
            return false;
        }

        // Recursive cases
        if (!s1.isEmpty() && s1.charAt(0) == s3.charAt(0)) {
            if (isInterleave(s1.substring(1), s2, s3.substring(1))) {
                return true;
            }
        }

        if (!s2.isEmpty() && s2.charAt(0) == s3.charAt(0)) {
            if (isInterleave(s1, s2.substring(1), s3.substring(1))) {
                return true;
            }
        }

        return false;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        // Input strings
        String s1 = scanner.next();
        String s2 = scanner.next();
        String s3 = scanner.next();

        // Output result
        System.out.println(isInterleave(s1, s2, s3) ? "True" : "False");
    }
}

